The implementation becomes surprisingly small.
var evalRPN = function (tokens) {
temp_arr = []; var ans = 0; for (i = 0; i < tokens.length; i++) { if (tokens[i] === '+') { let one = temp_arr.pop(); // second operand
let two = temp_arr.pop(); // first operand ans = Number(two) + Number(one); temp_arr.push(ans); } else if (tokens[i] === '-') { let one = temp_arr.pop(); // second operand
let two = temp_arr.pop(); // first operand ans = Number(two) - Number(one); temp_arr.push(ans); } else if (tokens[i] === '*') { let one = temp_arr.pop(); // second operand
let two = temp_arr.pop(); // first operand ans = Number(two) * Number(one); temp_arr.push(ans); } else if (tokens[i] === '/') { let one = temp_arr.pop(); // second operand
let two = temp_arr.pop(); // first operand ans = Math.trunc(Number(two) / Number(one)); temp_arr.push(ans); } else { temp_arr.push(tokens[i]); }
} if (tokens.length == 1) {
return Number(tokens[0]);
} return ans;
};One detail stood out while writing it.
The first value popped from the stack isn’t the first operand.
It’s the second.
That’s why the order matters.
let one = temp_arr.pop(); // second operand
let two = temp_arr.pop(); // first operandFor addition and multiplication, swapping them changes nothing.
For subtraction and division, it changes everything.
That small detail explains why many first attempts fail.
